return [{ json: { html: `<!DOCTYPE html>
<html lang="th">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1,user-scalable=no">
<title>ติดตามช่าง — SK ICE</title>
<link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css"/>
<script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>
<style>
*{margin:0;padding:0;box-sizing:border-box}
html,body{height:100%;overflow:hidden;font-family:'Helvetica Neue',Arial,sans-serif;background:#F0F4F8}
body{display:flex;flex-direction:column}
.hdr{background:linear-gradient(135deg,#1E3A5F,#2E6DA4);padding:13px 16px;color:#fff;text-align:center;flex-shrink:0}
.hdr h1{font-size:17px;font-weight:700}.hdr p{font-size:12px;color:#A8D5F0;margin-top:2px}
.sbar{background:#fff;padding:11px 16px;display:flex;align-items:center;gap:10px;box-shadow:0 2px 6px rgba(0,0,0,.12);flex-shrink:0}
.si{font-size:26px}.sinfo{flex:1}
.st{font-size:15px;font-weight:700;color:#2C3E50}
.ss{font-size:12px;color:#888;margin-top:2px;display:flex;align-items:center;gap:5px}
.dot{display:inline-block;width:8px;height:8px;border-radius:50%;background:#27AE60;flex-shrink:0}
.dot.off{background:#ccc}
@keyframes pulse{0%,100%{opacity:1}50%{opacity:.4}}
.dot.on{animation:pulse 1.5s infinite}
.tag{font-size:11px;background:#EEF4FF;color:#2E6DA4;padding:3px 8px;border-radius:10px;font-weight:700;flex-shrink:0}
/* open-in-browser bar */
.open-bar{display:flex;gap:8px;padding:8px 12px;background:#FFF8E1;border-bottom:1px solid #FFE082;flex-shrink:0}
.open-bar button{flex:1;border:none;border-radius:8px;padding:9px 6px;font-size:13px;font-weight:700;cursor:pointer}
.btn-chrome{background:#4285F4;color:#fff}
.btn-safari{background:#006CFF;color:#fff}
.wrap{flex:1;position:relative;min-height:0}
#map{width:100%;height:100%}
/* FAB buttons */
.fabs{position:absolute;bottom:20px;right:14px;z-index:1000;display:flex;flex-direction:column;gap:10px;align-items:flex-end}
.fab{border:none;border-radius:50px;padding:11px 16px;font-size:14px;font-weight:700;cursor:pointer;box-shadow:0 3px 12px rgba(0,0,0,.25);display:flex;align-items:center;gap:6px;white-space:nowrap}
.fab-tech{background:#1E3A5F;color:#fff}
.fab-me{background:#2E6DA4;color:#fff}
/* Loading overlay */
#loading{position:absolute;inset:0;background:rgba(255,255,255,.9);display:flex;flex-direction:column;align-items:center;justify-content:center;z-index:999;font-size:15px;color:#666;gap:10px}
#loading span{font-size:40px}
</style>
</head>
<body>

<div class="hdr">
  <h1>🧊 SK ICE — ติดตามช่าง</h1>
  <p id="hdr-sub">กำลังโหลด...</p>
</div>

<!-- Open in browser bar (shown on mobile) -->
<div class="open-bar" id="open-bar" style="display:none">
  <button class="btn-chrome" onclick="openChrome()">🟢 เปิดใน Chrome</button>
  <button class="btn-safari" onclick="openSafari()">🧭 เปิดใน Safari</button>
</div>

<div class="sbar">
  <div class="si" id="s-icon">🚗</div>
  <div class="sinfo">
    <div class="st" id="s-text">กำลังเดินทาง</div>
    <div class="ss">
      <span class="dot on" id="dot"></span>
      <span id="s-sub">กำลังโหลดตำแหน่ง...</span>
    </div>
  </div>
  <span class="tag" id="job-tag">-</span>
</div>

<div class="wrap">
  <div id="loading"><span>📍</span>กำลังโหลดแผนที่...</div>
  <div id="map"></div>
  <div class="fabs">
    <button class="fab fab-tech" id="btn-tech" onclick="focusTech()" style="display:none">🚗 ตำแหน่งช่าง</button>
    <button class="fab fab-me" onclick="centerMe()">📍 จุดของฉัน</button>
  </div>
</div>

<script>
// ───── config ─────
const BASE = 'https://skgroup.app.n8n.cloud/webhook';
const GPS_POS_URL = 'https://script.google.com/macros/s/AKfycby4bz_lqC2mVSd1PTN6Qa0v-debtTZmxKa2A6VlnXL0qxJHHQR5ghe7bvQqe3JR1jWK/exec';
const POLL_MS = 60000; // poll every 60s

// ───── URL params ─────
const p   = new URLSearchParams(location.search);
const JOB = (p.get('job_id') || p.get('work') || '').trim();

document.getElementById('hdr-sub').textContent = JOB ? 'งาน: ' + JOB : 'ไม่ระบุงาน';
document.getElementById('job-tag').textContent  = JOB || '-';

// ───── Leaflet map ─────
const map = L.map('map', { zoomControl: true, attributionControl: false });
L.tileLayer(
  'https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png',
  { maxZoom: 19, subdomains: 'abcd' }
).addTo(map);
map.setView([13.75, 100.5], 13);
document.getElementById('loading').style.display = 'none';

// ───── icons ─────
const techIcon = L.divIcon({
  html: '<div style="font-size:30px;line-height:1;filter:drop-shadow(1px 2px 3px rgba(0,0,0,.45))">🚗</div>',
  className: '', iconSize: [34, 34], iconAnchor: [17, 17], popupAnchor: [0, -18]
});
const doneIcon = L.divIcon({
  html: '<div style="font-size:30px;line-height:1">✅</div>',
  className: '', iconSize: [34, 34], iconAnchor: [17, 17]
});
const meIcon = L.divIcon({
  html: '<div style="width:16px;height:16px;background:#2E6DA4;border:3px solid #fff;border-radius:50%;box-shadow:0 0 0 4px rgba(46,109,164,.25)"></div>',
  className: '', iconSize: [16, 16], iconAnchor: [8, 8]
});

let techMarker = null;
let meMarker   = null;
let myLat = null, myLng = null;
let techLat = null, techLng = null;
let firstLoad = true;
let pollTimer = null;
let done = false;

// ───── browser detection ─────
(function(){
  const ua = navigator.userAgent || '';
  const isInApp = /Line\\/|FBAN|FBAV|FB_IAB|Instagram|Snapchat|Twitter|MicroMessenger/.test(ua)
    || (/(iPhone|iPod|iPad)/.test(ua) && !/Safari\\//.test(ua) && /AppleWebKit/.test(ua));
  const isMobile = /iPhone|iPad|iPod|Android/.test(ua);
  if(isInApp || isMobile) {
    document.getElementById('open-bar').style.display = 'flex';
  }
})();

function openChrome(){
  const u = location.href.replace('https://','googlechromes://').replace('http://','googlechrome://');
  location.href = u;
  setTimeout(()=>{ copyURL(); }, 2000);
}
function openSafari(){
  copyURL();
  alert('วาง URL ใน Safari แล้วเปิดครับ');
}
function copyURL(){
  const url = location.href;
  if(navigator.clipboard && navigator.clipboard.writeText){
    navigator.clipboard.writeText(url).then(()=>alert('✅ Copy แล้ว!\\nวางใน Chrome หรือ Safari'));
  } else { prompt('Copy URL:', url); }
}

// ───── fetch position ─────
function fetchPosition() {
  if (!JOB) {
    document.getElementById('s-sub').textContent = 'ไม่มีรหัสงาน';
    return;
  }
  fetch(GPS_POS_URL + '?job_id=' + encodeURIComponent(JOB), { redirect: 'follow' })
    .then(r => { if(!r.ok) throw new Error(r.status); return r.json(); })
    .then(data => { updateMap(data); updateStatus(data); })
    .catch(() => {
      document.getElementById('s-sub').textContent = 'ไม่สามารถโหลดข้อมูล — ลองใหม่...';
    });
}

function updateMap(d) {
  if (!d.found || !d.lat || !d.lng || d.lat === 0) return;
  techLat = d.lat; techLng = d.lng;
  const ll = [d.lat, d.lng];
  const icon = (d.status === 'completed') ? doneIcon : techIcon;
  const popup = '<b>' + (d.tech_name || 'ช่าง') + '</b><br>สถานะ: ' + fmtStatus(d.status) + '<br>อัปเดต: ' + fmtTime(d.timestamp);

  if (!techMarker) {
    techMarker = L.marker(ll, { icon }).addTo(map);
    techMarker.bindPopup(popup);
    document.getElementById('btn-tech').style.display = 'flex';
  } else {
    techMarker.setLatLng(ll);
    techMarker.setIcon(icon);
    techMarker.setPopupContent(popup);
  }
  if (firstLoad) {
    map.setView(ll, 15);
    firstLoad = false;
  }
}

function updateStatus(d) {
  const st  = d.status || 'traveling';
  const icon = document.getElementById('s-icon');
  const text = document.getElementById('s-text');
  const sub  = document.getElementById('s-sub');
  const dot  = document.getElementById('dot');

  if (st === 'completed') {
    icon.textContent = '✅';
    text.textContent = 'งานเสร็จแล้ว!';
    sub.textContent  = 'เสร็จเรียบร้อย — ขอบคุณที่ใช้บริการ SK ICE ครับ';
    dot.className    = 'dot off';
    if (!done) { done = true; clearInterval(pollTimer); }
  } else if (st === 'arrived') {
    icon.textContent = '🔧';
    text.textContent = 'ช่างถึงที่แล้ว!';
    sub.textContent  = 'กำลังดำเนินการ';
    dot.className    = 'dot off';
  } else {
    icon.textContent = '🚗';
    text.textContent = 'กำลังเดินทางมาหาคุณ';
    sub.textContent  = 'อัปเดตล่าสุด: ' + fmtTime(d.timestamp);
    dot.className    = 'dot on';
  }
}

// ───── focus on tech ─────
function focusTech() {
  if (techLat !== null) map.setView([techLat, techLng], 16);
}

// ───── center on customer ─────
function centerMe() {
  if (myLat !== null) {
    map.setView([myLat, myLng], 17);
    meMarker.openPopup();
    return;
  }
  if (!navigator.geolocation) { alert('เบราว์เซอร์ไม่รองรับ GPS'); return; }
  navigator.geolocation.getCurrentPosition(
    pos => {
      myLat = pos.coords.latitude;
      myLng = pos.coords.longitude;
      if (!meMarker) {
        meMarker = L.marker([myLat, myLng], { icon: meIcon }).addTo(map);
        meMarker.bindPopup('<b>ตำแหน่งของคุณ</b>').openPopup();
      } else {
        meMarker.setLatLng([myLat, myLng]);
        meMarker.openPopup();
      }
      map.setView([myLat, myLng], 17);
    },
    () => { alert('ไม่สามารถหาตำแหน่งของคุณได้\\nกรุณาเปิด GPS แล้วลองใหม่'); },
    { enableHighAccuracy: true, timeout: 12000 }
  );
}

// ───── helpers ─────
function fmtTime(ts) {
  if (!ts) return '-';
  try { return new Date(ts).toLocaleTimeString('th-TH', { hour: '2-digit', minute: '2-digit' }); }
  catch(e) { return ts; }
}
function fmtStatus(st) {
  return st === 'completed' ? 'เสร็จแล้ว' : st === 'arrived' ? 'ถึงแล้ว' : 'กำลังเดินทาง';
}

// ───── start ─────
fetchPosition();
pollTimer = setInterval(fetchPosition, POLL_MS);
</script>
</body>
</html>
` } }];
